1	// claim-office.ts
2	
3	type Scenario = {
4	  customer: { yearsWithMHPCO: number };
5	  steps: { op: string; items: { type: string }[] }[];
6	};
7	
8	type ScenarioResult = {
9	  results: { premium: number }[];
10	};
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	};
17	
18	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
19	const PROCESSING_FEE = 5;
20	
21	export const processScenario = (scenario: Scenario): ScenarioResult => {
22	  const items = scenario.steps[0].items;
23	  const basePremium = items.length === 0 ? 0 : BASE_PREMIUMS[items[0].type];
24	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
25	  const premium = basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
26	  return { results: [{ premium }] };
27	};
